import{_ as e,o as r,c as p,a2 as t}from"./chunks/framework.ZhLefgN8.js";const c=JSON.parse('{"title":"追缴保证金规则","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"margin/margin-call.md","filePath":"zh-CN/margin/margin-call.md"}'),i={name:"margin/margin-call.md"};function l(o,a,n,h,d,$){return r(),p("div",null,[...a[0]||(a[0]=[t('<h1 id="追缴保证金规则" tabindex="-1">追缴保证金规则 <a class="header-anchor" href="#追缴保证金规则" aria-label="Permalink to &quot;追缴保证金规则&quot;">​</a></h1><p>当账户股权资产低于维持保证金要求时，平台将发出追缴保证金（Margin Call）通知，要求在规定时间内补足差额，否则可能触发强制平仓。</p><h2 id="追缴触发条件" tabindex="-1">追缴触发条件 <a class="header-anchor" href="#追缴触发条件" aria-label="Permalink to &quot;追缴触发条件&quot;">​</a></h2><p>股权资产 &lt; 维持保证金要求（MM）</p><h2 id="追缴处理期限" tabindex="-1">追缴处理期限 <a class="header-anchor" href="#追缴处理期限" aria-label="Permalink to &quot;追缴处理期限&quot;">​</a></h2><p>收到追缴通知后，须在 3 个交易日内（含当日）补足差额。</p><p>追缴金额 = 维持保证金要求 - 股权资产（高于两者差额）</p><h2 id="可采取的措施" tabindex="-1">可采取的措施 <a class="header-anchor" href="#可采取的措施" aria-label="Permalink to &quot;可采取的措施&quot;">​</a></h2><p>存入现金：增加股权资产，降低保证金缺口。</p><p>卖出持仓：降低保证金要求。</p><p>所需卖出市值 ≤ (初始保证金要求 - 股权资产) ÷ IM 系数</p><h2 id="强制平仓触发条件" tabindex="-1">强制平仓触发条件 <a class="header-anchor" href="#强制平仓触发条件" aria-label="Permalink to &quot;强制平仓触发条件&quot;">​</a></h2><p>股权资产 &lt; 强平保证金要求（FM）时，平台可能即时强制平仓，无需等待 3 个交易日。</p><p>以下高风险情况可能不等待追缴期，直接触发强平：</p><p>末日期权（到期日当天的期权）持仓</p><p>市场出现极端波动</p><p>持仓流动性不足，无法正常变现</p><h2 id="完整示例" tabindex="-1">完整示例 <a class="header-anchor" href="#完整示例" aria-label="Permalink to &quot;完整示例&quot;">​</a></h2><p>账户存入现金 $10,000，同时持有 A 股票市值 $5,000（IM 30% / MM 25%）。</p><p>使用融资购入 B 股票，买入价 $25,000（IM 50% / MM 45%）。</p><p>之后 B 股票市值下跌至 $19,500。</p><p>此时各项指标：</p><p>股权资产 = $10,000（现金）+ $5,000（A）+ $19,500（B）- $25,000（融资结欠）= $9,500</p><p>维持保证金要求 = $5,000 × 25% + $19,500 × 45% = $1,250 + $8,775 = $10,025</p><p>股权资产 $9,500 &lt; 维持保证金要求 $10,025，触发追缴。</p><p>追缴金额 = $10,025 - $9,500 = $525（实际追缴金额高于此差额，需补至初始保证金水平）</p><p>若选择卖出 B 股票来满足追缴：</p><p>所需卖出市值 = (初始保证金要求 - 股权资产) ÷ IM 系数</p><p>初始保证金要求 = $5,000 × 30% + $19,500 × 50% = $1,500 + $9,750 = $11,250</p><p>所需卖出市值 ≤ ($11,250 - $9,500) ÷ 50% = $1,750 ÷ 50% = $3,500</p><p>即卖出至少 $3,500 市值的 B 股票，可使账户恢复至初始保证金要求以上。</p><p>实际追缴金额及截止时间请以账户内通知为准。</p><h2 id="相关文档" tabindex="-1">相关文档 <a class="header-anchor" href="#相关文档" aria-label="Permalink to &quot;相关文档&quot;">​</a></h2><ul><li><a href="/wiki/margin/账户风控状态">账户风控状态</a> — 安全/预警/危险四级风控状态与截止时间说明</li><li><a href="/wiki/margin/融资额度与保证金规则">融资额度与保证金规则</a> — IM/MM/FM 保证金系数定义与购买力计算</li></ul>',34)])])}const m=e(i,[["render",l]]);export{c as __pageData,m as default};
